+async function withTimeout<T>(promise: Promise<T>, timeoutMs: number): Promise<T | null> {
+  return await new Promise<T | null>((resolve) => {
+    let settled = false;
+    const timer = setTimeout(() => {
+      settled = true;
+      resolve(null);
+    }, timeoutMs);
+
+    promise
+      .then((value) => {
+        if (settled) return;
+        clearTimeout(timer);
+        resolve(value);
+      })
+      .catch(() => {
+        if (settled) return;
+        clearTimeout(timer);
+        resolve(null);
+      });
+  });
+}

