+function uniqueTrimerRatioAt(seq: string, start: number, windowSize: number): number {
+  const maxPossible = Math.min(64, windowSize - 2);
+  if (maxPossible <= 0) return 0;
+
+  let seenLo = 0;
+  let seenHi = 0;
+
+  let rolling = 0;
+  let valid = 0;
