+    if (rolling < 32) {
+      seenLo |= 1 << rolling;
+    } else {
+      seenHi |= 1 << (rolling - 32);
+    }
+  }
+
+  const unique = popcount32(seenLo) + popcount32(seenHi);
+  return unique / maxPossible;
